arguments.file_text:
@using sv_4fb5b172b6c84c0da146228907d54db6.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h5 class="card-title mb-0">Reference @(Index + 1)</h5>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Full Name</label>
                <input class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input class="form-control" placeholder="e.g., Former Manager" @bind="Reference.Relationship" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

.step-indicator {
    background: var(--bs-light, #f8f9fa);
    border-radius: 0.5rem;
    padding: 1rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    counter-reset: step;
}

.step {
    flex: 1;
    text-align: center;
    position: relative;
    opacity: 0.45;
}

.step + .step::before {
    content: "";
    position: absolute;
    top: 15px;
    left: -50%;
    width: 100%;
    height: 2px;
    background: var(--bs-border-color, #dee2e6);
    z-index: 0;
}

.step.completed + .step::before,
.step.active + .step::before {
    background: var(--bs-primary, #0d6efd);
}

.step.completed + .step.completed::before {
    background: var(--bs-success, #198754);
}

.step.active {
    opacity: 1;
}

.step.completed {
    opacity: 1;
}

.step-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border-radius: 50%;
    background: var(--bs-secondary-bg, #e9ecef);
    color: var(--bs-secondary-color, #6c757d);
    font-weight: 600;
    font-size: 0.875rem;
    position: relative;
    z-index: 1;
}

.step.active .step-badge {
    background: var(--bs-primary, #0d6efd);
