{"file_text": "<h3>Cover Letter</h3>
<p class="text-secondary">Write a cover letter to accompany your application.</p>

<div class="mb-3">
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              @bind="CoverLetter" @bind:event="oninput"
