@using sv_4fb5b172b6c84c0da146228907d54db6.Models

<h3>Personal Information</h3>
<p class="text-secondary">Please provide your contact details.</p>

<div class="row g-3 mb-4">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control @(errors.ContainsKey("FullName") ? "is-invalid" : "")"
               @bind="Model.FullName" @bind:event="oninput" />
        @if (errors.TryGetValue("FullName", out var nameErr))
        {
            <div class="invalid-feedback">@nameErr</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email"
               class="form-control @(errors.ContainsKey("Email") ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (errors.TryGetValue("Email", out var emailErr))
        {
            <div class="invalid-feedback">@emailErr</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel"
               class="form-control @(errors.ContainsKey("Phone") ? "is-invalid" : "")"
               @bind="Model.Phone" @bind:event="oninput" />
        @if (errors.TryGetValue("Phone", out var phoneErr))
        {
            <div class="invalid-feedback">@phoneErr</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control @(errors.ContainsKey("Address") ? "is-invalid" : "")"
               @bind="Model.Address" @bind:event="oninput" />
        @if (errors.TryGetValue("Address", out var addrErr))
        {
            <div class="invalid-feedback">@addrErr</div>
        }
    </div>
</div>

@if (isValidating)
{
    <div class="text-info mb-3">
        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        Validating email…
    </div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private Dictionary<string, string> errors = new();
    private bool isValidating;

    private async Task HandleNext()
    {
        errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName))
            errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Model.Email))
            errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone))
            errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Model.Address))
            errors["Address"] = "Address is required.";

        if (errors.Count > 0) return;

        isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                errors["Email"] = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            isValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

