toolArgs.file_text:
@using sv_4fb5b172b6c84c0da146228907d54db6.Models

<h3>Review & Submit</h3>
<p class="text-secondary">Please review your application before submitting.</p>

@if (submitted)
{
    <div class="alert alert-success text-center py-4">
        <h4 class="alert-heading">Application Submitted!</h4>
        <p>Your application has been received. Your confirmation number is:</p>
        <p class="display-6 fw-bold">@applicationId</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @PersonalInfo.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @PersonalInfo.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @PersonalInfo.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @PersonalInfo.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-secondary">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(submitError))
    {
        <div class="alert alert-danger">@submitError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel PersonalInfo { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnSubmit { get; set; }

    private bool isSubmitting;
    private bool submitted;
    private int applicationId;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;
        try
        {
            await OnSubmit.InvokeAsync(0);
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    public void ShowConfirmation(int id)
    {
        applicationId = id;
        submitted = true;
        StateHasChanged();
    }
}

