@page "/apply"
@rendermode InteractiveServer
@using sv_4fb5b172b6c84c0da146228907d54db6.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h1 class="mb-4">Job Application</h1>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo" ApplicationService="ApplicationService" OnNext="() => AdvanceTo(2)" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries" OnNext="() => AdvanceTo(3)" OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <ReferencesStep References="references" OnNext="() => AdvanceTo(4)" OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter" OnNext="() => AdvanceTo(5)" OnBack="() => GoToStep(3)" />
            break;
        case 5:
            <ReviewStep @ref="reviewStepRef"
                        PersonalInfo="personalInfo" WorkEntries="workEntries"
                        References="references" CoverLetter="coverLetter"
                        OnEdit="GoToStep" OnBack="() => GoToStep(4)"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private ReviewStep? reviewStepRef;

    private void AdvanceTo(int step)
    {
        completedSteps.Add(currentStep);
        currentStep = step;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task SubmitApplication(int _)
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        var id = await ApplicationService.SubmitApplicationAsync(application);
        reviewStepRef?.ShowConfirmation(id);
    }
}

